'use client';

import { Button } from '@/components/ui/button';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger
} from '@/components/ui/dialog';
import { Menu } from 'lucide-react';

import { ConfirmationDialog } from './confirmation-dialog';
import { DeleteDialog } from './delete-dialog';
import { FeedbackDialog } from './feedback-dialog';
import { LoginDialog } from './login-dialog';
import { PaymentDialog } from './payment-dialog';
import { SettingsDialog } from './settings-dialog';
import { ShareDialog } from './share-dialog';
import { SubscribeDialog } from './subscribe-dialog';
import { TermsDialog } from './terms-dialog';
import { WelcomeDialog } from './welcome-dialog';

export function ComponentDrawer() {
  return (
    <Dialog>
      <DialogTrigger asChild>
        <Button>
          <Menu className="mr-2 h-4 w-4" />
          Open Dialog Drawer
        </Button>
      </DialogTrigger>
      <DialogContent className="data-[state=closed]:slide-out-to-right data-[state=open]:slide-in-from-right fixed top-0 right-0 h-full max-h-screen w-full max-w-sm translate-x-0 translate-y-0 gap-0 rounded-none border-r-0 p-0 sm:rounded-l-lg">
        <DialogHeader className="border-b p-6">
          <DialogTitle>Dialog Examples</DialogTitle>
        </DialogHeader>
        <div className="grid gap-3 overflow-y-auto p-6">
          <TermsDialog />
          <LoginDialog />
          <ConfirmationDialog />
          <DeleteDialog />
          <SubscribeDialog />
          <ShareDialog />
          <FeedbackDialog />
          <SettingsDialog />
          <PaymentDialog />
          <WelcomeDialog />
        </div>
      </DialogContent>
    </Dialog>
  );
}

export default ComponentDrawer;
